<template>
  <div id="app">
    <bar/>
    <navi v-if='isRouterAlive'></navi>
    <router-view v-if='login'></router-view>
    <login v-if='!login && !reg'></login>
    <register v-if='reg'></register>
    <!-- <single-answer/> -->
  </div>
</template>

<script>
import Question from './components/Question'
import Navi from './components/Navi'
import Home from './components/Home'
import Login from './components/Login'
import Register from './components/Register'
import Answer from './components/Answer'
import Bar from './components/Bar'
import axios from 'axios'

export default {
  name: 'App',
  components: {
    Question,Home,Login,Register,Answer,Navi,Bar
  },
  provide(){
    return{
      reload:this.reload
    }
  },
  data(){
    return{
      isRouterAlive:true,
      login: false,
      reg:false
    }
  },
  created(){
    axios.get('https://wd6653727231vwclvk.wilddogio.com/condition.json')
    .then((data)=>{
      this.login = data.data.login
      this.reg = data.data.reg
    })
  },
  methods:{
    reload:function(){
      this.isRouterAlive=false
      this.$nextTick(function(){
        this.isRouterAlive=true
      })
    }
  }
}
</script>

<style>
 html{
  background: url(assets/bg.png);
 }
 body{
  margin: 0;
  padding: 0;
 }
</style>



