<template>
	<div id="navi">
		<router-link to='/'><img src="../assets/logo.png"></router-link>
		<h2>你好！{{condition.name}}</h2>
		<router-link to='/login' id='login' v-if='!condition.login'>登录/注册</router-link>
		<p v-if='condition.login' @click.prevent='quit'>退出登录</p>
	</div>
</template>


<script>
import axios from 'axios'
export default{
	name:'navi',
	data(){
		return{
			condition:{},
			id:this.$route.params.id
		}
	},
	created(){
		axios.get('https://wd6653727231vwclvk.wilddogio.com/condition.json')
		.then((data)=>{
			this.condition=data.data;
		})
	},
	methods:{
		quit:function(){
			axios.get('https://wd6653727231vwclvk.wilddogio.com/condition.json')
			.then((data)=>{
				this.condition.name='';
				this.condition.login=false;
			})
			axios.patch('https://wd6653727231vwclvk.wilddogio.com/condition.json',{name:'',login:false})
			.then(()=>{
				location.reload();
			})
		}
	}
}
	
</script>


<style scoped>
#navi{
	width: 100%;
	height: 64px;
	background: #fff;
	margin: 0;
	padding: 5px;
	border: 0;
	box-shadow: 0px 2px 2px #ccc;
	box-sizing: border-box;
	position: fixed;
	top: 0;
}
img{
	width: 48px;
	height: 48px;
	float: left;
	margin-left: 11%;
}
h2{
	display: inline-block;
	margin: 0 20px;
	line-height: 54px;
	padding: 0;
	float: left;
	color: rgb(31, 78, 121);
}
#login, p{
	float: right;
	line-height: 54px;
	margin: 0;
	margin-right: 11%;
	text-decoration: none;
	color: #888;
	cursor: pointer;
}
</style>


