<template>
  <div id="home">
  	<h2>Enjoy yourselves here!</h2>
    <input type="text" name="" placeholder="搜索..." v-model='search'>
    <div id="ques">
      <div v-for='question in filteredQuestions' :key='question.title' class="singleQues" @mouseenter='longer($event)' @mouseleave='shorter($event)'>
        <div class="cir"></div>
        <router-link v-bind:to="'/question/' + question.id">
          <h3>{{question.title}}</h3>
        </router-link>
        <p>提问人：{{question.author}}</p>
        <article>{{question.describe}}</article>
      </div>
    </div>
    <div id="info" ref='info'>
      <div id="personal">
        <div class="cir" id="cir"></div>
        <p>我的提问</p>
        <p>我的回答</p>
        <p>我顶的回答</p>
        <p>我踩的回答</p>
      </div>
      <div id="pic">
        <ul ref='pic'>
          <li><img src="../assets/1.jpg"></li><li><img src="../assets/2.jpeg"></li><li><img src="../assets/3.jpeg"></li>
        </ul>
      </div>
    </div>
    
  </div>
</template>

<script>
import axios from 'axios'
export default {
  name: 'home',
  data () {
    return {
      questions:[],
      search:''
    }
  },
  created(){
    axios.get('https://wd6653727231vwclvk.wilddogio.com/posts.json')
    .then(function(data){
      return data.data;
    })
    .then((data) =>{
      var questionsArray = [];
      for(let key in data){
        data[key].id = key;
        questionsArray.push(data[key]);
      }
      this.questions = questionsArray;
    })
  },
  mounted(){
    window.addEventListener('scroll', this.fix);
    this.change();
  },
  computed:{
    filteredQuestions: function(){
      return this.questions.filter((question => {
        return question.title.match(this.search)
      }))
    }
  },
  destroyed () {
    window.removeEventListener('scroll', this.fix);
  },
  methods:{
    change:function(){
      var e =this.$refs.pic;
      var long = 0;
      var timer = setInterval(function(){ 
        long -= 250;
        if (long == -750) {
          long = 0;
        }
        e.style.left = long + 'px';
      }, 3000)
    },
    fix:function(){
      // console.log(document.documentElement.scrollTop);
      // console.log(this.$refs.info);
      if (document.documentElement.scrollTop >= 100) {
        this.$refs.info.style.top = document.documentElement.scrollTop - 100 + 'px';
      }else {
        this.$refs.info.style.top = 0;
      }
    },
    longer:function(){
      event.currentTarget.style.marginLeft = -50 + 'px';
    },
    shorter:function(){
      event.currentTarget.style.marginLeft = 0;
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
#home{
  width: 75%;
  margin: 70px auto;
}
h2{
  color: #888;
  padding-top: 20px;
}
input{
  width: 300px;
  height: 30px;
  font-size: 16px;
  margin-bottom: 20px;
  padding-left: 5px;
  border: none;
  border-radius: 5px;
  box-shadow: 2px 2px 2px #ccc inset;
}
#ques{
  display: inline-block;
  width: 70%;
  margin: 0;
  padding: 0;
  border: none;
}
.singleQues{
  width: 100%;
  margin: 5px 0;
  background: #fff;
  border-radius: 5px;
  padding: 10px;
  box-shadow: 2px 2px 2px #ccc;
  box-sizing: border-box;
  padding: 0 40px 15px;
  /*position: relative;*/
  transition-duration: 1s;
}
h3{
  margin: 10px;
  color: rgb(31, 78, 121);
}
#ques p{
  margin: 10px;
  color: #888;
}
article{
  margin: 10px;
  font-size: 14px;
}
a{
  text-decoration: none;
  color: #000;
}
.ask{
  display: block;
  text-decoration: none;
  color: #fff;
  background: rgb(31, 78, 121);
  width: 84px;
  height: 24px;
  line-height: 24px;
  text-align: center;
  border-radius: 12px;
  margin: 10px 0;
}
.cir{
  width: 20px;
  height: 20px;
  border-radius: 10px;
  border: none;
  background: url(../assets/bg.png);
  box-shadow: 2px 2px 2px #ccc inset;
  padding: 0;
  display: inline-block;
  margin: 20px 0 0 -10px;
}
#info{
  width: 250px;
  display: inline-block;
  position: relative;
  top: 0;
  margin: 5px 0 0 15px;
  vertical-align: top;
}
#cir{
  margin: 20px 0 10px 15px;
}
#personal{
  width: 100%;
  height: 300px;
  border-radius: 5px;
  display: inline-block; 
  background: #fff;
  box-shadow: 2px 2px 2px #ccc;
  box-sizing: border-box;
}
#personal p{
  color: #888;
  height: 48px;
  text-align: center;
  line-height: 48px;
  margin: 0px;
  padding: 0px;
}
#personal p:hover{
  color: #fff;
  background: rgb(31, 78, 121);
  text-align: center;
  cursor: pointer;
  border-radius: 5px;
}
#pic{
  width: 250px;
  height: 167px;
  margin-top: 30px;
  border-radius: 5px;
  box-shadow: 2px 2px 2px #ccc;
  overflow: hidden;
}
ul{
  list-style: none;
  width: 750px;
  margin: 0;
  padding: 0;
  position: relative;
  transition-duration: 1s;
  left: 0;
}
li{
  display: inline-block;
  margin: 0;
  padding: 0;
}
img{
  width: 250px;
}
</style>



