<template>
  <div id="show-answer">
    <div id="question">
      <h2>{{question.title}}</h2>
      <article>{{question.describe}}</article>
      <label>分类:</label>
      <ul>
        <li v-for = 'category in question.categories' :key='category'>{{category}}</li>
      </ul>
      <router-link  v-bind:to="id +'/answer'" class='add'>添加回答</router-link>
    </div>
  	
    <div v-for='answer in question.answers' class="singleAnswer">
      <span>{{answer.author}}</span>
      <article>{{answer.content}}</article>
      <button @click="approval($event)">顶</button>
      <button @click="disapproval($event)">踩</button>
    </div>
  </div>
</template>

<script>
import axios from 'axios'
export default {
  name: 'show-answer',
  data () {
    return {
      id: this.$route.params.id,
      question:{}
    }
  },
  created(){
    axios.get('https://wd6653727231vwclvk.wilddogio.com/posts/' + this.$route.params.id + '.json')
    .then((data) =>{
      // console.log(this);
      this.question = data.data;
    })
  },
  methods:{
    approval(event){
      let cur = event.currentTarget;
      if (event.currentTarget.innerHTML == '顶') {
        cur.style.background = 'rgb(31, 78, 121)';
        cur.style.color = '#fff';
        cur.innerHTML = '已顶';
        cur.style.width = '48px';
        cur.nextElementSibling.innerHTML = '踩';
        cur.nextElementSibling.style.color = '#666';
        cur.nextElementSibling.style.width = '36px';
        cur.nextElementSibling.style.background = '#ddd';
      }else {
        cur.style.background = '#ddd';
        cur.style.color = '#666';
        cur.innerHTML = '顶';
        cur.style.width = '36px';
      }
    },
    disapproval(){
      let cur = event.currentTarget;
      if (event.currentTarget.innerHTML == '踩') {
        cur.style.background = 'rgb(31, 78, 121)';
        cur.style.color = '#fff';
        cur.innerHTML = '已踩';
        cur.style.width = '48px';
        cur.previousElementSibling.innerHTML = '顶';
        cur.previousElementSibling.style.color = '#666';
        cur.previousElementSibling.style.width = '36px';
        cur.previousElementSibling.style.background = '#ddd';
      }else {
        cur.style.background = '#ddd';
        cur.style.color = '#666';
        cur.innerHTML = '踩';
        cur.style.width = '36px';
      }
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
#show-answer{
  width: 75%;
  margin: 70px auto;
}
#question{
  width: 100%;
  padding: 20px;
  background: #fff;
  border-radius: 5px;
  box-shadow: 2px 2px 2px #ccc;
  box-sizing: border-box;
}
.singleAnswer{
  width: 100%;
  margin: 5px 0;
  padding: 20px;
  padding-bottom: 10px;
  background: #fff;
  border-radius: 5px;
  box-shadow: 2px 2px 2px #ccc;
  box-sizing: border-box;
}
h2{
  color: rgb(31, 78, 121);
}
article{
  margin: 10px 0;
  font-size: 14px;
}
ul,label{
  display: inline-block;
  padding: 0;
  color: #888;
}
li{
  display: inline-block;
  list-style-type: none;
  margin-left: 15px;
}
a{
  text-decoration: none;
  font-size: 12px;
  color: #666;
  display: inline-block;
  padding-top: 15px;
}
span{
  color: rgb(31, 78, 121);
  font-weight: bolder;
  font-size: 20px;
}
.add{
  display: block;
  text-decoration: none;
  color: #fff;
  background: rgb(31, 78, 121);
  width: 94px;
  height: 24px;
  line-height: 24px;
  text-align: center;
  border-radius: 12px;
  margin-bottom: 10px;
  font-size: 14px;
  padding: 0;
}
button{
  background: #ddd;
  color: #666;
  border: 0;
  border-radius: 5px;
  height: 24px;
  width: 36px;
  line-height: 24px;
  margin: 10px 10px 0 0;
}
</style>



