<template>
  <div id="bar">
  	<ul>
		<div id="wrap">
			<div id="group" ref='group'>
				<li id="backTop" @click='backTop()'>顶</li>
    			<router-link v-bind:to="'/ask'"><li class="kind">去</li></router-link>
    			<router-link v-bind:to="'/ask'"><li class="kind">提</li></router-link>
    			<router-link v-bind:to="'/ask'"><li class="kind">问</li></router-link>
			</div>
			
		</div>
		<li id="more" @mouseenter='turn($event)' @mouseleave='back($event)' @click='change()'>导</li>
	</ul>
  </div>
</template>

<script>
export default {
  name: 'bar',
  data () {
    return {
    	release: false
    }
  },
  methods:{
  	turn:function(){
  		event.currentTarget.style.transform = 'rotate(360deg)';
  		event.currentTarget.style.transitionDuration = '1s';
  	},
  	back:function(){
  		event.currentTarget.style.transform = 'rotate(0deg)';
  		event.currentTarget.style.transitionDuration = '1s';
  	},
  	change:function(){
  		if (this.release) {	
  			this.$refs.group.style.top = 0;
  			this.release = !this.release;
  		}else {
  			this.$refs.group.style.top = 126 + 'px';
  			this.release = !this.release;
  		}
  	},
  	backTop:function(){
  		var speed = 50;
		var back = setInterval(function(){
			document.documentElement.scrollTop -= speed;
			if (document.documentElement.scrollTop == 0) {
				clearInterval(back);
			}
		}, 20);
  	}
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
ul{
	margin: 0;
	padding: 0;
	position: fixed;
	right: 10px;
	bottom: 27%;
	overflow: hidden;
}
li{
	border-radius: 50%;
	width: 36px;
	height: 36px;
	border: none;
	background: rgb(31, 78, 121);
	text-align: center;
	color: #fff;
	font-size: 20px;
	margin-top: 6px;
	line-height: 36px;
	display: block;
	cursor: pointer;
	font-size: 18px;
	position: relative;
}
#wrap{
	position: relative;
	transition-duration: 1s;
	height: 186px;
	top: 18px;
	overflow: hidden;
}
#group{
	position: relative;
	transition-duration: 1s;
	top: 126px;
}
</style>



