<template>
  <div id="answer">
  	<form v-if='!submitted'>
      <h2>欢迎自由交流！</h2>
      <!-- <h3>{{question.title}}</h3> -->
      <textarea  placeholder="友善的观点是交流的起点" v-model='newAnswer.content'></textarea>
  		<button v-on:click.prevent = 'patch'>提交</button>
  	</form>
    <h3 v-if='submitted'>提交成功</h3>
  </div>
</template>

<script>
import axios from 'axios'
export default {
  name: 'answer',
  data () {
    return {
     id: this.$route.params.id,
     question:{},
     newAnswer:{
      author:'',
      content:'',
      num:0,
      good:0,
      bad:0
     },
     submitted:false
    }
  },
  created(){
    axios.get('https://wd6653727231vwclvk.wilddogio.com/posts/' + this.id + '.json')
    .then((data) =>{
      this.question = data.data;
    })
    axios.get('https://wd6653727231vwclvk.wilddogio.com/condition.json')
    .then((data) =>{
      this.newAnswer.author = data.data.name;
    })
  },
  methods:{
  	patch:function(){
      var answersArray = [];
      for(let key in this.question.answers){
        answersArray.push(this.question.answers[key]);
      }
      if (this.newAnswer.content == '') {
        alert('回答不能为空');
        return false;
      }else {
        this.newAnswer.num = answersArray.length + 1;
        answersArray.push(this.newAnswer);
        axios.patch('https://wd6653727231vwclvk.wilddogio.com/posts/' + this.id + '.json', {answers:answersArray})
        .then((data) =>{
          this.submitted = true;
        });
      }
  	}
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
#answer{
  width: 75%;
  margin: 70px auto;
}
h2{
  color: #888;
  padding-top: 20px;
}
input[type = 'text'],textarea{
  padding: 5px;
  display: block;
  margin: 10px 0;
  width: 100%;
  font-size: 16px;
}
textarea{
  height: 150px;
}
#checkboxes label{
  margin: 0px;
}
#checkboxes input{
  margin-right: 10px;
}
button{
  width: 100px;
  height: 40px;
  font-size: 16px;
  margin: 10px 0; 
  background: rgb(31, 78, 121);
  color: #fff;
  border: none;
  border-radius: 5px;
}
h3{
  text-align: center;
  margin-top: 50px;
}
</style>


